VALUES
  ('real-estate-moex-01372', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '下列有關書信的用語，何者正確？', '["對他人稱自己的母親用「令堂」", "學生寫信給老師，自稱「授業」", "信封寫受信人姓名、稱呼及「拜啟」，以示禮敬", "寫信給父母親，結尾的問候語可用「叩請  福安」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01373', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「碧玉妝成一樹高，萬條垂下綠絲縧。不知細葉誰裁出？二月春風似剪刀。」詩中所詠之物是：', '["榕鬚", "松樹", "蔦蘿", "柳樹"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01374', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '洛夫寫於1985年的〈剔牙〉詩句如下：「中午／全世界的人都在剔牙／以潔白的牙籤／安詳地在／剔他 們／潔白的牙齒  衣索匹亞的一群兀鷹／從一堆屍體中／飛起／排排蹲在／疏朗的枯樹上／也在剔牙／ 以一根根瘦小的／肋骨。」下列何者與詩的第二段「衣索匹亞的一群兀鷹」意涵無關？', '["死亡", "恐怖", "饑餓", "慌亂 60210"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01375', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '鄭板橋詩：「紙花如雪滿天飛，嬌女鞦韆打四圍。五色羅裙風擺動，好將蝴蝶鬭春歸。」郭麟吟詩： 「一百四日小寒食，冶遊爭上白浪河。紙鳶兒子鞦韆女，亂比新來春燕多。」二詩中所描寫的童玩是：', '["毽子", "風箏", "風車", "燈籠"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01376', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '吳健雄是二十世紀傑出的女物理學家，曾經參與研發原子彈的曼哈頓計畫。她少年時代親受胡適指導， 在她即將赴美留學時，胡適給她的教誨是：「凡治學問，功力之外，還需要天才。龜兔之喻，是勉勵中 人以下之語，也是警惕天才之語，有兔子的天才，加上烏龜的功力，定可無敵於一世。僅有功力，可無 大過，而未必有大成功。你是很聰明的人，千萬珍重自愛，將來成就未可限量。這還不是我要對你說的 話。我要對你說的是希望你能利用你的海外住留期間，多留意此邦文物，多讀文史的書，多讀其他科學， 使胸襟闊大，使見解高明……做一個博學的人……凡第一流的科學家，都是極淵博的人，取精而用弘， 由博而反約，故能有大成功。」（摘自江才健《吳健雄—物理科學的第一夫人》） 依上文，胡適最重視的是：', '["應善用自己的天賦，再加上勤勞，必定可以成就一番事業", "作為一流的科學家，除了聰明與努力之外，還要懂得潔身自愛", "能夠到海外求學，吸取外邦的經驗與新知，是成就大事業之所必須", "專精的能力固然重要，但是廣泛閱讀、關注文化及開拓視野也很重要"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01377', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '林語堂〈說避暑之益〉：「除非現代文明能夠給人人一塊宅地，讓小孩去翻筋斗捉蟋蟀弄得一身骯髒痛 快，那種文明不會被我重視。我說明所以搬去那所樓層的緣故，是因那房後面有一片荒園，有橫倒的樹 幹，有碧綠的池塘」，其所謂之「文明」，最重要的特質為何？', '["不與自然隔絕", "居者皆有其屋", "肯定遊戲需求", "重視兒童權益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01378', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「在同一條街上有荷蘭西班牙日本中國建築是正常的，清一色的單調建築違反歷史法則─我們的城鎮歌 聲喑啞，沒有旋律沒有變化；在舊社區中有新社區，四合院農田鄰接麥當勞也是正常的，只見新人笑不 見舊人哭，這也是違反人情法則─我們的城鎮荒腔走板，沒有歷史沒有記憶。讓城鎮唱出它們的歌，古 調今調皆宜，牧歌搖滾兼容並蓄。那將是多麼盛大悅耳！」（周芬伶〈城鎮在唱歌〉） 上述內容，作者欲表達的是：', '["我們的城鎮「盛大悅耳」，是因為常在同一條街上有荷蘭西班牙日本中國建築", "我們的城鎮「無古建築」，是因為不知歷史記憶的重要性，以為清一色新才是新", "我們的城鎮「歌聲喑啞，沒有旋律沒有變化」，是在倡議讓樂音飄揚於街頭巷尾", "我們的城鎮「荒腔走板，沒有歷史沒有記憶」，是在抨擊貴古賤今的陳腐思想 60210"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01379', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「想想，六嬸自工地返家天已昏暝，她一臉塵灰一身土泥，幾雙嗷嗷待哺眼睛張望著她，她所思慮的是如 何在最短時間內張羅出一頓可以填飽肚子的食物，而非精心烹調，所以桌上總有幾樣罐頭食品：罐頭菜心 罐頭脆瓜罐頭燒鰻或是罐頭三文魚，滷蛋炒蛋荷包蛋變換著，炒空心菜炒花椰菜炒高麗菜，滷肉，黃昏市 場買來的切豆乾滷海帶，幾個孩子把一碗菜夾得山尖，坐到電視機前盯著《無敵鐵金剛》、《海王子》看 得忘了扒飯。 而一早同六嬸一起上工的男人返家後，可能先沖熱水澡，有熱騰騰菜肴等在餐桌，飯後踅到附近柑仔店啜飲 米酒嚼花生米閒嗑牙……冬天到了，樹木落光了葉子減少養分損失，僅留著枝幹看似蕭條，其實它的打算不 在目前，而在來春。六嬸總說，你們好好讀冊，看後擺日子能不能好過一點。」（王盛弘〈清糜〉） 下列敘述，何者不符合上文意旨？', '["女性在家庭經濟的需求下也需外出工作", "側面寫出男性與女性在家庭中的勞務分工之不均", "現代罐頭食品出現在餐桌，侵蝕了婦女對食物的支配權", "婦女除了出外勞動外，回到家常常超時進行家務工作"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01380', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '國民信託在國外已行之有年，成果豐碩。這項運動源自英國，1895 年由律師、牧師加上女性社會改革人 士的三人小組共同發起。他們認為，具歷史價值或自然美景的地區應歸全民共有，一人一元的萬人力量， 大於一人萬元的一萬倍！至今，英國國民信託機構名下的土地面積占全國2.7%，已是民間最大「地主」。 緣此，以《彼得兔》（The Tale of Peter Rabbit）聞名全球的英國作家波特（Beatrix Potter）的湖區房舍至 今原封不動保存完善；搖滾團體披頭四（Beatles）故居，經典老歌依然傳唱。日本動畫導演宮崎駿，擔 任龍貓兒童信託基金董事長，集資近四億日圓買下11片森林；更在2010年1月買下琦玉縣峽山地區， 也就是他親自執導、轟動全球的早年名作動畫主角龍貓的故鄉。 依據報導內容，下列敘述何者錯誤？', '["披頭四故居因國民信託得以保存", "龍貓動畫因國民信託資金，終得完製上映", "公民加入信託行列，是管理公共財的一種方式", "保存歷史、自然等珍貴文物，是每個人都能盡力的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01381', 'real-estate', 'real-estate-moex-105-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '余以採硫來居臺郡兩月，為購布，購油，購糖，鑄大鑊，冶刀斧、鋤、杓，規大小木桶，製秤、尺、斗、 斛，種種畢備。布以給番人易硫土；油與大鑊，所以煉硫；糖給工匠頻飲并浴體，以辟硫毒；鋤平土築 基；刀斧伐薪薙草；杓出硫於鑊；小桶凝硫，大桶貯水；秤、尺、斗、斛，以衡量諸物。又購脫粟、鹽 豉、筐、釜、碗、箸等，率為百人具，計費九百八十金，買一巨舶載之。入資什七，覺舟重不任載，心 竊疑焉。遂止弗入，更買一舶，為載所餘，費半前舶。或曰：「舟有大小，受載有量，今頗未盡量，何 徒費為？」余曰：「吾忽心動，方欲使兩舶中分之，匪直載所餘也。」言者匿笑去。（節選自：郁永河 《裨海紀遊‧卷中》） 依照郁永河自述，其既已「買一巨舶載之」。而後，「更買一舶」的原因為何？', '["言者匿笑，不堪其擾", "舟量所限，僅入資什七", "忽然心動，覺舟重不任載", "為辟硫毒，與番人分乘二舟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "24f9c540d4ee", "answer_pdf_sha1": "84e67e00c5ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
